#!/bin/bash
# Phase 3 Testing Guide - Real-Time Alerts
# Run this to understand how to test the alert system on localhost:4200

set -e

echo "=========================================="
echo "Phase 3: Real-Time Alerts Testing Guide"
echo "=========================================="
echo ""
echo "Prerequisites:"
echo "  ✓ npm start running on localhost:4200"
echo "  ✓ Backend API running on localhost:8080"
echo "  ✓ WebSocket connection active"
echo ""
echo "Testing Checklist:"
echo ""
echo "1. VERIFY ALERT COMPONENTS LOADED"
echo "   - Navigate to http://localhost:4200/live/drivers"
echo "   - Open Chrome DevTools (F12)"
echo "   - Go to Console tab"
echo "   - Type: document.querySelectorAll('app-driver-alert-toast').length"
echo "   - Expected: 0 (no alerts yet)"
echo ""

echo "2. TEST SPEEDING ALERT (Speed > 80 km/h)"
echo "   Method A: Backend Simulation"
echo "   - Run: curl -X POST http://localhost:8080/api/admin/drivers/1/speed-sim -d '{\"speed\": 95}'"
echo "   - Expected: Yellow toast appears top-right saying 'Driver 1 speeding: 95 km/h'"
echo "   - Expected: Toast disappears after 5 seconds (auto-close)"
echo ""
echo "   Method B: Browser Console (Mock)"
