echo "     const service = ng.getComponent(document.querySelector('app-driver-gps-tracking')).driverAlertService;"
echo "     service.checkAndEmitAlerts(1, { speed: 95, batteryLevel: 75 });"
echo "   - Expected: Yellow toast appears immediately"
echo ""

echo "3. TEST COOLDOWN ENFORCEMENT (No spam within 30s)"
echo "   - Trigger same alert 3 times quickly"
echo "   - Expected: Toast only appears once, next 2 are ignored (check console)"
echo "   - Wait 30 seconds"
echo "   - Trigger again"
echo "   - Expected: Toast appears again (cooldown expired)"
echo ""

echo "4. TEST HARSH BRAKING ALERT (Acceleration < -6 m/s²)"
echo "   - Paste in Console:"
echo "     service.checkAndEmitAlerts(2, { acceleration: -7.5, speed: 50 });"
echo "   - Expected: Yellow toast with 'harsh braking: 7.5 m/s²'"
echo ""

echo "5. TEST BATTERY LOW ALERT (Battery < 15%)"
echo "   - Paste in Console:"
echo "     service.checkAndEmitAlerts(3, { batteryLevel: 12, speed: 40 });"
echo "   - Expected: Yellow toast with 'battery low: 12%'"
echo ""

echo "6. TEST SNOOZE BUTTON"
echo "   - Trigger speeding alert (or wait for one)"
echo "   - Click 'Snooze' button on toast"
echo "   - Expected: Toast disappears"
echo "   - Expected: Alert removed from activeAlerts map"
echo "   - Check console: ng.getComponent(...).activeAlerts.size → should decrease"
echo ""

echo "7. TEST DISMISS BUTTON"
echo "   - Trigger another alert"
echo "   - Click '✕' (dismiss) button"
echo "   - Expected: Toast immediately disappears"
echo "   - Expected: Alert removed from activeAlerts map"
echo ""

echo "8. TEST TOAST STYLING"
echo "   - All toasts should:"
echo "     • Appear in top-right corner"
echo "     • Have yellow background (warning severity)"
echo "     • Have white text"
echo "     • Slide in smoothly from right (300ms animation)"
echo "     • Show timestamp using current time"
echo "   - Open DevTools Elements tab"
echo "   - Inspect <app-driver-alert-toast> element"
echo "   - Verify Tailwind classes applied:"
echo "     bg-yellow-100, border-l-4, border-yellow-500, text-yellow-800"
echo ""

echo "9. TEST MULTIPLE ALERTS (UI Stack)"
echo "   - Trigger 3+ different alerts quickly"
echo "   - Expected: Each toast stacks on top (may overlap)"
echo "   - Expected: Each has independent snooze/dismiss"
echo ""

echo "10. TEST ALERT HISTORY"
echo "    - Open Console and run:"
echo "      const service = ng.getComponent(document.querySelector('app-driver-gps-tracking')).driverAlertService;"
echo "      service.alerts$.value"
echo "    - Expected: Logged array of all alerts triggered (up to 100)"
echo "    - Expected: Each has id, driverId, type, severity, timestamp, message"
echo ""

